        // ✅ Zero timeout = non-blocking poll
        struct timeval timeout;
        timeout.tv_sec = 0;
        timeout.tv_usec = 0;  // Return immediately

        int ready = select(max_fd + 1, &read_fds, NULL, NULL, &timeout);

