int send_all(int fd, const char* data, int len) {
    int total_sent = 0;

    while (total_sent < len) {
        int n = send(fd, data + total_sent, len - total_sent, 0);

        if (n < 0) {
            if (errno == EAGAIN || errno == EWOULDBLOCK) {
                // Would block - could use select() here
                usleep(1000);  // Brief pause
                continue;
            }
            return -1;  // Real error
        }

        total_sent += n;
    }

    return total_sent;
}

