        char buf[4096];
        recv(fd, buf, sizeof(buf), 0);

        // Return to pool
        pool.release(fd);

        // Periodic cleanup
        if (i % 10 == 0) {
            pool.cleanup_idle();
        }

        // Small delay
        usleep(100000);  // 100ms
    }

