    int optval = 1;
    setsockopt(fd, IPPROTO_TCP, TCP_CORK, &optval, sizeof(optval));

    send(fd, headers.c_str(), headers.size(), MSG_NOSIGNAL);
    send(fd, body.c_str(), body.size(), MSG_NOSIGNAL);

    // Disable cork (flush)
    optval = 0;
    setsockopt(fd, IPPROTO_TCP, TCP_CORK, &optval, sizeof(optval));
}

